mapper.select:
SELECT COUNT(*)
FROM post_attachments
WHERE post_id = #{postId}

mapper.insert:
INSERT INTO post_attachments (
    post_id, uploader_id, original_name, stored_name, file_path, file_size
)
VALUES (
    #{postId}, #{uploaderId}, #{originalName}, #{storedName}, #{filePath}, #{fileSize}
)

mapper.update:
UPDATE post_attachments
SET original_name = #{originalName},
    stored_name = #{storedName},
    file_path = #{filePath},
    file_size = #{fileSize}
WHERE attachment_id = #{attachmentId}

mapper.delete:
DELETE FROM post_attachments
WHERE attachment_id = #{attachmentId}
AND post_id = #{postId}
